prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?modelId . }
  FILTER(CONTAINS(STR(?modelId), "0ae2e7d8093840cc8a65c475b6275cae") || CONTAINS(STR(?model), "0ae2e7d8093840cc8a65c475b6275cae"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
  { ?elem tai:belongsTo ?model . }
  UNION
  { ?model tai:belongsTo ?elem . }
  UNION
  { ?model ?prop ?elem . FILTER(isURI(?elem)) }
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 100

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayDir ?defaultFlow ?flowName WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo <https://www.teamingai-project.eu/belongsTo> <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-89c72dc1-47d9-4218-bcfb-be69509c6221> .
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway <https://www.teamingai-project.eu/belongsTo> ?choreo .
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDir . }
  OPTIONAL { ?gateway bboExt:default ?defaultFlow . }
  OPTIONAL { ?defaultFlow bbo:name ?flowName . }
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?start ?startType ?end ?endType WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo <https://www.teamingai-project.eu/belongsTo> <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-89c72dc1-47d9-4218-bcfb-be69509c6221> .

  OPTIONAL {
    ?start a bboExt:StartEvent .
    ?start <https://www.teamingai-project.eu/belongsTo> ?choreo .
    ?start a ?startType .
  }

  OPTIONAL {
    ?end a bboExt:EndEvent .
    ?end <https://www.teamingai-project.eu/belongsTo> ?choreo .
    ?end a ?endType .
  }
}
LIMIT 10
